import { useState, useEffect, useRef } from "react";
import * as store from "./tripsStore";

/* ============================================================
   FLORES TRAVEL AGENCY & STORE — sitio en React
   - Edita los viajes en el arreglo TRIPS
   - Cambia WHATSAPP por el número real (código de país + número)
   ============================================================ */

const LOGO = "data:image/png;base64,";

const WHATSAPP = "528332030033";

/* Catálogo base vacío: todos los viajes se administran desde el panel #admin. */
const TRIPS = [];

const fmt = (n) => "$" + n.toLocaleString("es-MX");

const fmtDate = (iso) =>
  new Date(iso + "T12:00:00").toLocaleDateString("es-MX", { day: "numeric", month: "long", year: "numeric" });

const fmtDateTime = (ms) =>
  new Date(ms).toLocaleString("es-MX", { day: "numeric", month: "short", hour: "2-digit", minute: "2-digit" });

/* Convierte un rango de fechas ISO al formato del sitio: "14 – 19 de agosto 2026" */
function fmtRange(startIso, endIso) {
  if (!startIso) return "";
  const s = new Date(startIso + "T12:00:00");
  const e = endIso ? new Date(endIso + "T12:00:00") : null;
  const month = (d) => d.toLocaleDateString("es-MX", { month: "long" });
  if (!e || e.getTime() === s.getTime()) {
    return `${s.getDate()} de ${month(s)} ${s.getFullYear()}`;
  }
  if (s.getFullYear() === e.getFullYear() && s.getMonth() === e.getMonth()) {
    return `${s.getDate()} – ${e.getDate()} de ${month(s)} ${s.getFullYear()}`;
  }
  if (s.getFullYear() === e.getFullYear()) {
    return `${s.getDate()} de ${month(s)} – ${e.getDate()} de ${month(e)} ${s.getFullYear()}`;
  }
  return `${s.getDate()} de ${month(s)} ${s.getFullYear()} – ${e.getDate()} de ${month(e)} ${e.getFullYear()}`;
}

/* Redimensiona y comprime la imagen subida a un JPEG pequeño (data URL).
   Se guarda dentro del documento de Firestore, que admite máx. ~1 MB. */
async function compressImage(file, maxSize = 1200) {
  const bitmap = await createImageBitmap(file);
  const scale = Math.min(1, maxSize / Math.max(bitmap.width, bitmap.height));
  const canvas = document.createElement("canvas");
  canvas.width = Math.round(bitmap.width * scale);
  canvas.height = Math.round(bitmap.height * scale);
  canvas.getContext("2d").drawImage(bitmap, 0, 0, canvas.width, canvas.height);
  bitmap.close?.();
  let quality = 0.75;
  let dataUrl = canvas.toDataURL("image/jpeg", quality);
  while (dataUrl.length > 700_000 && quality > 0.3) {
    quality -= 0.15;
    dataUrl = canvas.toDataURL("image/jpeg", quality);
  }
  if (dataUrl.length > 900_000) {
    throw new Error("La imagen es demasiado grande incluso comprimida. Usa una más pequeña.");
  }
  return dataUrl;
}

/* Texto de personas a partir de mín/máx: "2 – 6 personas" */
function fmtPeople(min, max) {
  let a = Number(min) || 0;
  let b = Number(max) || 0;
  if (!a && !b) return "";
  if (!a) a = b;
  if (b && b < a) [a, b] = [b, a];
  if (b && b !== a) return `${a} – ${b} personas`;
  return a === 1 ? "1 persona" : `${a} personas`;
}

/* Duración a partir del rango: "6 días · 5 noches" */
function calcDuration(startIso, endIso) {
  if (!startIso) return "";
  const start = new Date(startIso + "T12:00:00");
  const end = new Date((endIso || startIso) + "T12:00:00");
  const days = Math.round((end - start) / 86400000) + 1;
  if (days < 1) return "";
  if (days === 1) return "1 día";
  return `${days} días · ${days - 1} ${days === 2 ? "noche" : "noches"}`;
}

