/* Etiqueta de precio: "MXN / persona", "USD / viaje", etc. */
const priceLabel = (t) =>
  `${t.currency ?? "MXN"} / ${(t.priceMode ?? "person") === "total" ? "viaje" : "persona"}`;

/* ---------- tarjeta de viaje ---------- */
function TripCard({ trip, onOpen }) {
  return (
    <button className="card" aria-haspopup="dialog" onClick={() => onOpen(trip)}>
      <div className="card-media" style={{ backgroundImage: trip.img }}>
        <span className="tag">{trip.tag}</span>
      </div>
      <div className="card-body">
        <h3>{trip.title}</h3>
        <Destination to={trip.to} />
        <div className="meta">
          <span><CalIcon />{trip.dates}</span>
          <span><PeopleIcon />{trip.people}</span>
        </div>
        <div className="card-foot">
          <span className="price">{fmt(trip.price)} <small>{priceLabel(trip)}</small></span>
          <span className="more">Ver detalles →</span>
        </div>
      </div>
    </button>
  );
}

/* ---------- modal de detalle ---------- */
function TripModal({ trip, onClose }) {
  const closeRef = useRef(null);

  useEffect(() => {
    if (!trip) return;
    closeRef.current?.focus();
    document.body.style.overflow = "hidden";
    const onKey = (e) => e.key === "Escape" && onClose();
    document.addEventListener("keydown", onKey);
    return () => {
      document.body.style.overflow = "";
      document.removeEventListener("keydown", onKey);
    };
  }, [trip, onClose]);

  if (!trip) return null;

  const reserve = () => {
    const msg = encodeURIComponent(`Hola, me interesa el viaje "${trip.title}" (${trip.dates}).`);
    window.open(`https://wa.me/${WHATSAPP}?text=${msg}`, "_blank");
  };

  return (
    <div className="modal-backdrop open" onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div className="modal" role="dialog" aria-modal="true" aria-labelledby="m-title">
        <div className="modal-hero" style={{ backgroundImage: trip.img }}>
          <button ref={closeRef} className="modal-close" aria-label="Cerrar" onClick={onClose}>✕</button>
        </div>
        <div className="modal-body">
          <span className="eyebrow">{trip.tag}</span>
          <h3 id="m-title">{trip.title}</h3>
          <Destination to={trip.to} className="modal-route" />
          <div className="modal-meta">
            <div><b>Fechas</b><span>{trip.dates}</span></div>
            <div><b>Duración</b><span>{trip.duration}</span></div>
            <div><b>Personas</b><span>{trip.people}</span></div>
          </div>
          <p className="desc">{trip.desc}</p>
          <b className="inc-label">El viaje incluye</b>
          <ul className="includes">
            {trip.includes.map((i) => <li key={i}>{i}</li>)}
          </ul>
          <div className="modal-foot">
            <div className="price big">{fmt(trip.price)} <small>{priceLabel(trip)}</small></div>
            <button className="reserve" onClick={reserve}>Reservar por WhatsApp</button>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ---------- botón flotante de contacto (leads) ---------- */
const EMPTY_LEAD = { name: "", phone: "", tripId: "", message: "" };

function LeadWidget({ trips }) {
  const [open, setOpen] = useState(false);
  const [sent, setSent] = useState(false);
  const [busy, setBusy] = useState(false);
  const [form, setForm] = useState(EMPTY_LEAD);

  const set = (key) => (e) => setForm((f) => ({ ...f, [key]: e.target.value }));

  useEffect(() => {
    if (!open) return;
    const onKey = (e) => e.key === "Escape" && setOpen(false);
    document.addEventListener("keydown", onKey);
    return () => document.removeEventListener("keydown", onKey);
  }, [open]);

  const submit = async (e) => {
    e.preventDefault();
    setBusy(true);
    try {
      const trip = trips.find((t) => t.id === form.tripId);
      await store.addLead({
        name: form.name.trim(),
        phone: form.phone.trim(),
        tripId: form.tripId || null,
        tripTitle: trip?.title ?? null,
        message: form.message.trim(),
      });
      setForm(EMPTY_LEAD);
      setSent(true);
    } catch (err) {
      window.alert("No se pudo enviar tu solicitud. Inténtalo de nuevo o escríbenos por WhatsApp.");
      console.error("Error al enviar solicitud:", err);
    } finally {
      setBusy(false);
    }
  };

  return (
    <div className="lead-widget">
      {open && (
        <div className="lead-panel" role="dialog" aria-label="Solicitar que te contactemos">
          {sent ? (
            <div className="lead-sent">
              <b>¡Gracias! ✈️</b>
              <p>Recibimos tus datos y te contactaremos muy pronto.</p>
              <button className="reserve" onClick={() => { setSent(false); setOpen(false); }}>Cerrar</button>
            </div>
          ) : (
            <>
              <div className="lead-head">
                <b>¿Te ayudamos a elegir?</b>
                <span>Déjanos tus datos y te contactamos sin compromiso.</span>
              </div>
              <form onSubmit={submit}>
                <input required maxLength="120" placeholder="Tu nombre" aria-label="Nombre" value={form.name} onChange={set("name")} />
                <input required maxLength="30" type="tel" placeholder="Tu teléfono (WhatsApp)" aria-label="Teléfono" value={form.phone} onChange={set("phone")} />
                <select aria-label="Viaje de interés" value={form.tripId} onChange={set("tripId")}>
                  <option value="">Viaje de interés (opcional)</option>
                  {trips.map((t) => <option key={t.id} value={t.id}>{t.title}</option>)}
                </select>
                <textarea rows="2" maxLength="1000" placeholder="Mensaje (opcional)" aria-label="Mensaje" value={form.message} onChange={set("message")} />
                <button type="submit" className="reserve" disabled={busy}>{busy ? "Enviando…" : "Enviar"}</button>
              </form>
            </>
          )}
        </div>
      )}
      <button
        className="lead-fab"
        aria-label={open ? "Cerrar formulario de contacto" : "Solicitar que te contactemos"}
        aria-expanded={open}
        onClick={() => { setOpen((o) => !o); setSent(false); }}
      >
        {open ? (
          <span aria-hidden="true">✕</span>
        ) : (
          <svg viewBox="0 0 24 24" aria-hidden="true">
            <path d="M12 3C7 3 3 6.6 3 11c0 2.2 1 4.2 2.7 5.6-.1 1-.5 2.2-1.5 3.4 1.9-.2 3.4-.8 4.4-1.5.8.2 1.6.4 2.4.4 5 0 9-3.6 9-7.9S17 3 12 3z" />
            <path className="lead-fab-plane" d="M8 13.5l8-3.4-3.6 3.7-.8 2.1-.9-1.9-2.7-.5z" />
          </svg>
        )}
      </button>
    </div>
  );
}

/* ---------- inicio de sesión del panel ---------- */
function AdminLogin() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [busy, setBusy] = useState(false);

  const submit = async (e) => {
    e.preventDefault();
    setBusy(true);
    setError("");
    try {
      await store.login(email, password);
    } catch {
      setError("Correo o contraseña incorrectos.");
    } finally {
      setBusy(false);
    }
  };

  return (
    <main className="admin">
      <span className="eyebrow">Panel interno</span>
      <h2 className="title">Iniciar sesión</h2>
      <p className="admin-note">Este panel es solo para el equipo de la agencia.</p>
      <form className="admin-form login-form" onSubmit={submit}>
        <div className="field full">
          <label htmlFor="l-email">Correo</label>
          <input id="l-email" type="email" required autoComplete="username" value={email} onChange={(e) => setEmail(e.target.value)} />
        </div>
        <div className="field full">
          <label htmlFor="l-pass">Contraseña</label>
          <input id="l-pass" type="password" required autoComplete="current-password" value={password} onChange={(e) => setPassword(e.target.value)} />
        </div>
        <div className="admin-actions">
          <button type="submit" className="reserve" disabled={busy}>{busy ? "Entrando…" : "Entrar"}</button>
          {error && <span className="form-error" role="alert">{error}</span>}
        </div>
      </form>
    </main>
  );
}

/* ---------- panel de administración ---------- */
const EMPTY_FORM = {
  title: "", tag: "Playa", to: "", startDate: "", endDate: "",
  peopleMin: "", peopleMax: "", price: "", currency: "MXN", priceMode: "person",
  image: "", desc: "", includes: "",
  autoDelete: false,
};

function AdminView({ catalog, hiddenIds, customTrips, leads, onAdd, onUpdate, onDeleteCustom, onHide, onRestore, onDeleteLead, user, onLogout }) {
  const [form, setForm] = useState(EMPTY_FORM);
  const [saved, setSaved] = useState(false);
  const [editing, setEditing] = useState(null);
  const [imgBusy, setImgBusy] = useState(false);
  const formRef = useRef(null);
  const fileRef = useRef(null);

  const clearFileInput = () => {
    if (fileRef.current) fileRef.current.value = "";
  };

  const onFile = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setImgBusy(true);
    try {
      const dataUrl = await compressImage(file);
      setForm((f) => ({ ...f, image: dataUrl }));
    } catch (err) {
      clearFileInput();
      window.alert("No se pudo procesar la imagen: " + (err?.message ?? err));
    } finally {
      setImgBusy(false);
    }
  };

  const set = (key) => (e) => setForm((f) => ({ ...f, [key]: e.target.value }));

  const published = [...catalog.filter((t) => !hiddenIds.includes(t.id)), ...customTrips];
  const hidden = catalog.filter((t) => hiddenIds.includes(t.id));
  const editingCatalog = editing != null && catalog.some((c) => c.id === editing.id);

  const startEdit = (t) => {
    setEditing(t);
    setForm({
      title: t.title ?? "",
      tag: t.tag ?? "",
      to: t.to ?? "",
      startDate: t.startDate ?? "",
      endDate: t.endDate ?? "",
      peopleMin: t.peopleMin != null ? String(t.peopleMin) : "",
      peopleMax: t.peopleMax != null ? String(t.peopleMax) : "",
      price: t.price != null ? String(t.price) : "",
      currency: t.currency ?? "MXN",
      priceMode: t.priceMode ?? "person",
      image: t.img?.match(/url\('([^']+)'\)/)?.[1] ?? "",
      desc: t.desc ?? "",
      includes: (t.includes ?? []).join("\n"),
      autoDelete: Boolean(t.expires),
    });
    clearFileInput();
    formRef.current?.scrollIntoView({ behavior: "smooth", block: "start" });
  };

  const cancelEdit = () => {
    setEditing(null);
    setForm(EMPTY_FORM);
    clearFileInput();
  };

  const submit = async (e) => {
    e.preventDefault();
    const data = {
      tag: form.tag.trim() || "Otros",
      title: form.title.trim(),
      to: form.to.trim(),
      // Si no se eligen fechas al editar un viaje antiguo, se conserva su texto original.
      dates: form.startDate ? fmtRange(form.startDate, form.endDate) : (editing?.dates ?? ""),
      startDate: form.startDate || null,
      endDate: form.endDate || null,
      duration: form.startDate ? calcDuration(form.startDate, form.endDate) : (editing?.duration ?? ""),
      // Si no se capturan números al editar un viaje antiguo, se conserva su texto original.
      people: (form.peopleMin || form.peopleMax)
        ? fmtPeople(form.peopleMin, form.peopleMax)
        : (editing?.people ?? ""),
      peopleMin: Number(form.peopleMin) || null,
      peopleMax: Number(form.peopleMax) || null,
      price: Number(form.price) || 0,
      currency: form.currency,
      priceMode: form.priceMode,
      img: form.image
        ? `linear-gradient(rgba(10,79,83,.2),rgba(10,79,83,.2)),url('${form.image.replace(/["'()]/g, "")}')`
        : "linear-gradient(135deg,var(--lagoon),var(--lagoon-deep))",
      desc: form.desc.trim(),
      includes: form.includes.split("\n").map((s) => s.trim()).filter(Boolean),
      expires: form.autoDelete && form.startDate ? form.startDate : null,
    };
    try {
      if (editing && editingCatalog) {
        // El catálogo base vive en el código: se guarda una copia editada
        // como viaje propio y se oculta el original.
        await onAdd({ ...data, id: `custom-${Date.now()}` });
        await onHide(editing.id);
      } else if (editing) {
        await onUpdate({ ...data, id: editing.id });
      } else {
        await onAdd({ ...data, id: `custom-${Date.now()}` });
      }
      setEditing(null);
      setForm(EMPTY_FORM);
      clearFileInput();
      setSaved(true);
      setTimeout(() => setSaved(false), 2500);
    } catch (err) {
      window.alert("No se pudo guardar el viaje: " + (err?.message ?? err));
    }
  };

  return (
    <main className="admin">
      <span className="eyebrow">Panel interno</span>
      <h2 className="title">{editing ? "Editar viaje" : "Agregar viaje"}</h2>
      {editing ? (
        <p className="admin-note">
          Editando <b>{editing.title}</b>.
          {editingCatalog && " Es un viaje del catálogo base: al guardar, la versión editada lo reemplazará en la página pública."}
        </p>
      ) : (
        <p className="admin-note">
          Los viajes agregados aquí aparecen junto a los del catálogo en la página pública.
        </p>
      )}

      {store.usingFirebase ? (
        user && (
          <div className="admin-bar">
            <span>Sesión iniciada: <b>{user.email}</b></span>
            <button className="del" onClick={onLogout}>Cerrar sesión</button>
          </div>
        )
      ) : (
        <p className="admin-banner">
          Firebase no está configurado, así que los cambios se guardan solo en este navegador.
          Copia <code>.env.example</code> como <code>.env.local</code> con las credenciales de tu
          proyecto para activar la base de datos compartida.
        </p>
      )}

      <form className="admin-form" onSubmit={submit} ref={formRef}>
        <div className="field full">
          <label htmlFor="a-title">Título *</label>
          <input id="a-title" required value={form.title} onChange={set("title")} placeholder="Cancún todo incluido" />
        </div>
        <div className="field">
          <label htmlFor="a-tag">Categoría</label>
          <input id="a-tag" list="a-tags" value={form.tag} onChange={set("tag")} />
          <datalist id="a-tags">
            {[...new Set(catalog.map((t) => t.tag))].map((t) => <option key={t} value={t} />)}
          </datalist>
        </div>
        <div className="field">
          <label htmlFor="a-price">Precio *</label>
          <div className="price-row">
            <input id="a-price" required type="number" min="0" step="any" value={form.price} onChange={set("price")} placeholder="14900" />
            <select aria-label="Moneda" value={form.currency} onChange={set("currency")}>
              <option value="MXN">MXN</option>
              <option value="USD">USD</option>
            </select>
          </div>
        </div>
        <div className="field">
          <label htmlFor="a-pmode">El precio es</label>
          <select id="a-pmode" value={form.priceMode} onChange={set("priceMode")}>
            <option value="person">Por persona</option>
            <option value="total">Por viaje completo</option>
          </select>
        </div>
        <div className="field">
          <label htmlFor="a-to">Destino *</label>
          <input id="a-to" required value={form.to} onChange={set("to")} placeholder="Cancún, Q. Roo" />
        </div>
        <div className="field">
          <label htmlFor="a-start">Inicio del viaje{form.autoDelete ? " *" : ""}</label>
          <input id="a-start" type="date" required={form.autoDelete} value={form.startDate} onChange={set("startDate")} />
        </div>
        <div className="field">
          <label htmlFor="a-end">Fin del viaje</label>
          <input id="a-end" type="date" min={form.startDate || undefined} value={form.endDate} onChange={set("endDate")} />
        </div>
        <div className="field">
          <label htmlFor="a-duration">Duración (automática)</label>
          <input
            id="a-duration"
            disabled
            value={calcDuration(form.startDate, form.endDate)}
            placeholder="Se calcula con las fechas"
          />
        </div>
        <div className="field">
          <label htmlFor="a-pmin">Personas (mín – máx)</label>
          <div className="people-row">
            <input id="a-pmin" type="number" min="1" placeholder="Mín" aria-label="Personas mínimo" value={form.peopleMin} onChange={set("peopleMin")} />
            <span aria-hidden="true">–</span>
            <input id="a-pmax" type="number" min={form.peopleMin || 1} placeholder="Máx" aria-label="Personas máximo" value={form.peopleMax} onChange={set("peopleMax")} />
          </div>
        </div>
        <div className="field full">
          <label htmlFor="a-img">Imagen</label>
          <div className="img-row">
            <input id="a-img" ref={fileRef} type="file" accept="image/*" onChange={onFile} />
            {form.image && (
              <div className="img-preview" style={{ backgroundImage: `url('${form.image}')` }} />
            )}
            {form.image && (
              <button
                type="button"
                className="img-clear"
                onClick={() => { setForm((f) => ({ ...f, image: "" })); clearFileInput(); }}
              >
                Quitar
              </button>
            )}
          </div>
          {imgBusy && <span className="img-busy" role="status">Procesando imagen…</span>}
        </div>
        <div className="field full">
          <label htmlFor="a-desc">Descripción</label>
          <textarea id="a-desc" rows="3" value={form.desc} onChange={set("desc")} />
        </div>
        <div className="field full">
          <label htmlFor="a-inc">El viaje incluye (un elemento por línea)</label>
          <textarea id="a-inc" rows="4" value={form.includes} onChange={set("includes")} placeholder={"Vuelo redondo\n5 noches de hospedaje"} />
        </div>
        <div className="field full auto-del">
          <label className="check">
            <input
              type="checkbox"
              checked={form.autoDelete}
              onChange={(e) => setForm((f) => ({ ...f, autoDelete: e.target.checked }))}
            />
            <span>Eliminar automáticamente cuando comience el viaje</span>
          </label>
          {form.autoDelete && (
            <p className="auto-del-hint">
              {form.startDate
                ? `El viaje se eliminará de la página el ${fmtDate(form.startDate)}.`
                : "Se usará la fecha de inicio del viaje."}
            </p>
          )}
        </div>
        <div className="admin-actions">
          <button type="submit" className="reserve">{editing ? "Guardar cambios" : "Agregar viaje"}</button>
          {editing && <button type="button" className="cancel-edit" onClick={cancelEdit}>Cancelar</button>}
          {saved && <span className="saved-note" role="status">{editing ? "Cambios guardados ✓" : "Viaje guardado ✓"}</span>}
        </div>
      </form>

      <h2 className="title admin-list-title">Viajes publicados ({published.length})</h2>
      {published.length === 0 ? (
        <p className="empty">No hay viajes publicados.</p>
      ) : (
        <ul className="admin-list">
          {published.map((t) => {
            const isCustom = customTrips.some((c) => c.id === t.id);
            return (
              <li key={t.id} className="admin-item">
                <div className="admin-item-media" style={{ backgroundImage: t.img }} />
                <div>
                  <b>{t.title}</b>
                  <span>
                    {t.tag} · {t.to || "sin destino"} · {fmt(t.price)} {t.currency ?? "MXN"}
                    {t.expires && ` · se elimina el ${fmtDate(t.expires)}`}
                  </span>
                </div>
                <span className={`badge ${isCustom ? "custom" : ""}`}>{isCustom ? "Agregado" : "Catálogo"}</span>
                <button className="edit" onClick={() => startEdit(t)}>Editar</button>
                <button
                  className="del"
                  onClick={() => {
                    if (isCustom) {
                      if (window.confirm(`¿Eliminar definitivamente "${t.title}"? Esta acción no se puede deshacer.`)) {
                        onDeleteCustom(t.id);
                      }
                    } else {
                      onHide(t.id);
                    }
                  }}
                >
                  Eliminar
                </button>
              </li>
            );
          })}
        </ul>
      )}

      {hidden.length > 0 && (
        <>
          <h2 className="title admin-list-title">Eliminados del catálogo ({hidden.length})</h2>
          <p className="admin-note">
            Estos viajes forman parte del catálogo base del sitio; no aparecen en la página
            pública, pero puedes restaurarlos cuando quieras.
          </p>
          <ul className="admin-list">
            {hidden.map((t) => (
              <li key={t.id} className="admin-item muted">
                <div className="admin-item-media" style={{ backgroundImage: t.img }} />
                <div>
                  <b>{t.title}</b>
                  <span>{t.tag} · {t.to} · {fmt(t.price)} {t.currency ?? "MXN"}</span>
                </div>
                <button className="restore" onClick={() => onRestore(t.id)}>Restaurar</button>
              </li>
            ))}
          </ul>
        </>
      )}

      <h2 className="title admin-list-title">Solicitudes de contacto ({leads.length})</h2>
      <p className="admin-note">
        Personas que dejaron sus datos en el botón flotante del sitio para que las contactes.
      </p>
      {leads.length === 0 ? (
        <p className="empty">No hay solicitudes pendientes.</p>
      ) : (
        <ul className="admin-list">
          {leads.map((l) => {
            const digits = (l.phone ?? "").replace(/\D/g, "");
            const wa = digits.length === 10 ? `52${digits}` : digits;
            return (
              <li key={l.id} className="admin-item lead-item">
                <div>
                  <b>{l.name}</b>
                  <span>
                    {l.phone}
                    {l.tripTitle ? ` · ${l.tripTitle}` : ""}
                    {l.createdAt ? ` · ${fmtDateTime(l.createdAt)}` : ""}
                  </span>
                  {l.message && <span className="lead-msg">“{l.message}”</span>}
                </div>
                {wa && (
                  <a className="restore" href={`https://wa.me/${wa}`} target="_blank" rel="noopener noreferrer">
                    WhatsApp
                  </a>
                )}
                <button
                  className="del"
                  onClick={() => window.confirm(`¿Eliminar la solicitud de ${l.name}?`) && onDeleteLead(l.id)}
                >
                  Eliminar
                </button>
              </li>
            );
          })}
        </ul>
      )}
    </main>
  );
}

/* ---------- app ---------- */
export default function FloresTravel() {
  const [filter, setFilter] = useState("Todos");
  const [selected, setSelected] = useState(null);
  const [customTrips, setCustomTrips] = useState([]);
  const [hiddenIds, setHiddenIds] = useState([]);
  const [route, setRoute] = useState(() => window.location.hash);
  const [user, setUser] = useState(null);
  const [authReady, setAuthReady] = useState(!store.usingFirebase);
  const [leads, setLeads] = useState([]);

  useEffect(() => store.subscribeCustomTrips(setCustomTrips), []);
  useEffect(() => store.subscribeHiddenIds(setHiddenIds), []);

  // Las solicitudes solo pueden leerse con sesión iniciada.
  useEffect(() => {
    if (store.usingFirebase && !user) {
      setLeads([]);
      return;
    }
    return store.subscribeLeads(setLeads);
  }, [user]);
  useEffect(() => store.subscribeAuth((u) => { setUser(u); setAuthReady(true); }), []);

  // Con sesión iniciada, borra de la base los viajes ya vencidos.
  useEffect(() => {
    if (user) store.purgeExpiredTrips();
  }, [user]);

  // Revela secciones y tarjetas con un desvanecido suave al hacer scroll.
  useEffect(() => {
    const els = document.querySelectorAll("[data-reveal]:not(.revealed)");
    if (!els.length) return;
    if (!("IntersectionObserver" in window)) {
      els.forEach((el) => el.classList.add("revealed"));
      return;
    }
    const io = new IntersectionObserver(
      (entries) => {
        entries.forEach((en) => {
          if (en.isIntersecting) {
            en.target.classList.add("revealed");
            io.unobserve(en.target);
          }
        });
      },
      { threshold: 0.12, rootMargin: "0px 0px -36px 0px" },
    );
    els.forEach((el) => io.observe(el));
    return () => io.disconnect();
  });

  useEffect(() => {
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = "https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,300;9..144,400;9..144,500;9..144,600&family=Jost:wght@300;400;500;600&display=swap";
    document.head.appendChild(link);
    return () => link.remove();
  }, []);

  useEffect(() => {
    const onHash = () => setRoute(window.location.hash);
    window.addEventListener("hashchange", onHash);
    return () => window.removeEventListener("hashchange", onHash);
  }, []);

  const reportError = (err) =>
    window.alert("No se pudo guardar el cambio: " + (err?.message ?? err));

  const addTrip = (trip) => store.addTrip(trip);
  const updateTrip = (trip) => store.updateTrip(trip);
  const deleteTrip = (id) => store.deleteTrip(id).catch(reportError);
  const hideTrip = (id) => store.saveHiddenIds([...hiddenIds, id]).catch(reportError);
  const restoreTrip = (id) => store.saveHiddenIds(hiddenIds.filter((h) => h !== id)).catch(reportError);

  const trips = [...TRIPS.filter((t) => !hiddenIds.includes(t.id)), ...customTrips];
  const cats = ["Todos", ...new Set(trips.map((t) => t.tag))];
  const list = filter === "Todos" ? trips : trips.filter((t) => t.tag === filter);

  if (route === "#admin") {
    return (
      <div className="flores">
        <style>{CSS}</style>
        <header>
          <div className="nav">
            <a className="brand" href="#top">
              <img src={LOGO} alt="Logo de Flores Travel Agency" />
              <span className="brand-name">FLORES<span className="brand-sub">Panel de administración</span></span>
            </a>
            <a className="cta" href="#top" style={{ marginLeft: "auto" }}>← Volver al sitio</a>
          </div>
        </header>
        {!authReady ? (
          <main className="admin"><p className="empty">Cargando…</p></main>
        ) : store.usingFirebase && !user ? (
          <AdminLogin />
        ) : (
          <AdminView
            catalog={TRIPS}
            hiddenIds={hiddenIds}
            customTrips={customTrips}
            leads={leads}
            onAdd={addTrip}
            onUpdate={updateTrip}
            onDeleteCustom={deleteTrip}
            onHide={hideTrip}
            onRestore={restoreTrip}
            onDeleteLead={(id) => store.deleteLead(id).catch(reportError)}
            user={user}
            onLogout={store.logout}
          />
        )}
        <footer>
          <div className="foot-brand">FLORES · Travel Agency &amp; Store</div>
          <div>Panel interno</div>
        </footer>
      </div>
    );
  }

  return (
    <div className="flores">
      <style>{CSS}</style>

      <header>
        <div className="nav">
          <a className="brand" href="#top">
            <img src={LOGO} alt="Logo de Flores Travel Agency" />
            <span className="brand-name">FLORES<span className="brand-sub">Travel Agency &amp; Store</span></span>
          </a>
          <nav className="links" aria-label="Navegación principal">
            <a href="#viajes">Viajes</a>
            <a href="#nosotros">Nosotros</a>
            <a href="#contacto">Contacto</a>
          </nav>
          <a className="cta" href="#viajes">Ver viajes</a>
        </div>
      </header>

      <section className="hero" id="top">
        <div>
          <span className="eyebrow">Agencia de viajes · Tampico</span>
          <h1>Tu próximo destino <em>empieza aquí</em></h1>
          <p className="lead">Viajes en grupo, escapadas de playa y rutas internacionales, organizados de principio a fin. Tú solo haz la maleta.</p>
          <div className="hero-actions">
            <a className="btn solid" href="#viajes">Explorar viajes</a>
            <a className="btn ghost" href="#contacto">Habla con nosotros</a>
          </div>
        </div>
        <div className="hero-visual">
          <svg className="flight-path" viewBox="0 0 400 400" aria-hidden="true">
            <path d="M 30 320 C 80 140, 260 60, 380 110" />
            <g className="plane" transform="translate(368,104) rotate(24)">
              <path d="M0 0 L14 5 L2 8 L-1 13 L-3 8 L-9 7 Z" />
            </g>
          </svg>
          <img src={LOGO} alt="Flores Travel Agency & Store" />
        </div>
      </section>

      <section className="block" id="viajes">
        <div className="block-head" data-reveal>
          <div>
            <span className="eyebrow">Próximas salidas</span>
            <h2 className="title">Viajes disponibles</h2>
          </div>
          <p>Da clic en cualquier viaje para ver el detalle completo y aparta tu lugar.</p>
        </div>

        <div className="filters" data-reveal role="group" aria-label="Filtrar viajes por categoría">
          {cats.map((c) => (
            <button key={c} className={`chip ${c === filter ? "active" : ""}`} onClick={() => setFilter(c)}>
              {c}
            </button>
          ))}
        </div>

        {list.length > 0 ? (
          <div className="grid">
            {list.map((t, i) => (
              <div key={t.id} data-reveal style={{ transitionDelay: `${Math.min(i % 9, 6) * 70}ms` }}>
                <TripCard trip={t} onOpen={setSelected} />
              </div>
            ))}
          </div>
        ) : (
          <p className="empty">No hay viajes en esta categoría por ahora. Escríbenos y lo armamos para ti.</p>
        )}
      </section>

      <div className="about" id="nosotros">
        <div className="about-inner">
          <img src={LOGO} alt="" data-reveal />
          <div data-reveal style={{ transitionDelay: "120ms" }}>
            <span className="eyebrow">Nosotros</span>
            <h2>Viajar debería ser lo fácil</h2>
            <p>En Flores Travel Agency &amp; Store nos encargamos de todo: vuelos, hospedaje, traslados y actividades. Somos una agencia local que acompaña a cada viajero antes, durante y después del viaje, con atención personal y grupos que se sienten como familia.</p>
          </div>
        </div>
      </div>

      <section className="block" id="contacto">
        <div data-reveal>
          <span className="eyebrow">Contacto</span>
          <h2 className="title">Reserva tu lugar</h2>
        </div>
        <div className="contact-grid">
          <div className="contact-card" data-reveal><b>WhatsApp</b><a href={`https://wa.me/${WHATSAPP}`}>+52 833 203 0033</a></div>
          <div className="contact-card" data-reveal style={{ transitionDelay: "70ms" }}><b>Correo</b><a href="mailto:flores.travelagency@gmail.com">flores.travelagency@gmail.com</a></div>
          <div className="contact-card" data-reveal style={{ transitionDelay: "140ms" }}><b>Instagram</b><a href="https://www.instagram.com/florestravelagency?igsh=MXM4ejM5eTBidG1naQ==" target="_blank" rel="noopener noreferrer">@florestravelagency</a></div>
          <div className="contact-card" data-reveal style={{ transitionDelay: "210ms" }}><b>Oficina</b><span>Tampico, Tamaulipas · Lun–Sáb 10:00–19:00</span></div>
        </div>
      </section>

      <footer>
        <div className="foot-brand">FLORES · Travel Agency &amp; Store</div>
        <div>© 2026 Flores Travel Agency. Todos los derechos reservados. · <a className="foot-admin" href="#admin">Admin</a></div>
      </footer>

      <LeadWidget trips={trips} />
      <TripModal trip={selected} onClose={() => setSelected(null)} />
    </div>
  );
}

